   249	Typing::operator()(CallExpr* obj)
   250	{
   251	  ASSERT(obj->head);
   252	
   253	  obj->head = self(obj->head);
   254	  auto fexp = dynamic_cast<FunctionType*>(obj->head->type->texp);
   255	  if (fexp == nullptr)
   256	    ABORT();
   257	
   258	  auto f2p = make<ImplicitCastExpr>();
   259	  f2p->kind = ImplicitCastExpr::kFunctionToPointerDecay;
   260	  // 加上指针类型
   261	  auto type = make<Type>();
   262	  auto pointerType = make<PointerType>();
   263	  type->spec = obj->head->type->spec;
   264	  type->qual = obj->head->type->qual;
   265	  pointerType->sub = obj->head->type->texp;
   266	  type->texp = pointerType;
   267	
   268	  f2p->type = type;
   269	  f2p->sub = obj->head;
   270	  obj->head = f2p;
   271	
   272	  if (fexp->params.size() != obj->args.size())
   273	    ABORT();
   274	
   275	  for (int i = fexp->params.size(); --i != -1;) {
   276	    Expr lft;
   277	    lft.type = fexp->params[i];
   278	    lft.cate = Expr::Cate::kLValue;
   279	    obj->args[i] = assignment_cast(&lft, self(obj->args[i]));
   280	  }
   281	
   282	  obj->type = mTypeCache(obj->head->type->spec, Type::Qual(), fexp->sub);
   283	  obj->cate = Expr::Cate::kRValue;
   284	
   285	  return obj;
   286	}
